#!/usr/bin/env python3
"""
bootstrap_suprabank_ingest.py — SupraBank data ingestion pipeline for MABE.

Writes:
  core/suprabank_ingest.py          — ingestion module
  data/suprabank_cb_raw.json        — 1312 CB[5-8] entries at 25C water
  data/suprabank_cd_raw.json        — 400 CD entries at 25C water
  data/suprabank_mol_data.json      — SMILES for 743 guest molecules
  data/suprabank_pc_data.json       — pre-computed packing coefficients
  data/sasa_cache.json              — pre-computed SASA values
  data/hbd_cache.json               — pre-computed H-bond donor counts
  data/p28_suprabank_backsolve.json — PC_opt back-solve result
  data/suprabank_scoring_diagnostics.json
  tests/test_suprabank_ingest.py    — 10 validation tests

Source: suprabank.org, CC-BY-4.0, extracted 2026-03-17
Total: 1712 host-guest Ka values (1312 CB + 400 CD)
"""
import base64, os, sys

# Detect repo root
ROOT = os.path.dirname(os.path.abspath(__file__))
if not os.path.exists(os.path.join(ROOT, "core", "universal_schema.py")):
    ROOT = os.path.dirname(ROOT)
    if not os.path.exists(os.path.join(ROOT, "core", "universal_schema.py")):
        print("ERROR: Run from MABE repo root"); sys.exit(1)

FILES = {}
FILES["core/suprabank_ingest.py"] = ""
FILES["data/suprabank_cb_raw.json"] = ""
FILES["data/suprabank_cd_raw.json"] = ""
FILES["data/suprabank_mol_data.json"] = ""
FILES["data/suprabank_pc_data.json"] = ""
FILES["data/sasa_cache.json"] = ""
FILES["data/hbd_cache.json"] = ""
FILES["data/p28_suprabank_backsolve.json"] = ""
FILES["data/suprabank_scoring_diagnostics.json"] = ""
FILES["tests/test_suprabank_ingest.py"] = ""

n = 0
for rel_path, b64 in FILES.items():
    full = os.path.join(ROOT, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w", encoding="utf-8") as f:
        f.write(base64.b64decode(b64).decode("utf-8"))
    n += 1
    print(f"  written: {rel_path}")

print(f"\nBootstrap complete: {n} files written.")
print("Run: python -m pytest tests/test_suprabank_ingest.py -v")